     2→
     3→/// Screen position in points
     4→public struct Position: Equatable, Codable, Sendable {
     5→    public var x: Double
     6→    public var y: Double
     7→
     8→    public init(x: Double, y: Double) {
     9→        self.x = x
    10→        self.y = y
    11→    }
    12→
    13→    public static let zero = Position(x: 0, y: 0)
    14→
    15→    public func distance(to other: Position) -> Double {
    16→        let dx = other.x - x
    17→        let dy = other.y - y
    18→        return sqrt(dx * dx + dy * dy)
    19→    }
    20→
    21→    public func offset(dx: Double = 0, dy: Double = 0) -> Position {
    22→        Position(x: x + dx, y: y + dy)
    23→    }
    24→}
    25→
    26→/// Screen edge enumeration
    27→public enum ScreenEdge: String, CaseIterable, Codable, Sendable {
    28→    case top
    29→    case bottom
    30→    case left
    31→    case right
    32→
    33→    /// Opposite edge
    34→    public var opposite: ScreenEdge {
    35→        switch self {
    36→        case .top: return .bottom
    37→        case .bottom: return .top
    38→        case .left: return .right
    39→        case .right: return .left
    40→        }
    41→    }
    42→}
    43→
    44→/// Rectangle in screen coordinates
    45→public struct ScreenRect: Equatable, Codable, Sendable {
    46→    public var x: Double
    47→    public var y: Double
    48→    public var width: Double
    49→    public var height: Double
    50→
    51→    public init(x: Double, y: Double, width: Double, height: Double) {
    52→        self.x = x
    53→        self.y = y
    54→        self.width = width
    55→        self.height = height
    56→    }
    57→
    58→    public var minX: Double { x }
    59→    public var maxX: Double { x + width }
    60→    public var minY: Double { y }
    61→    public var maxY: Double { y + height }
    62→
    63→    public var center: Position {
    64→        Position(x: x + width / 2, y: y + height / 2)
    65→    }
    66→
    67→    public func contains(_ position: Position) -> Bool {
    68→        position.x >= minX && position.x <= maxX &&
    69→        position.y >= minY && position.y <= maxY
    70→    }
    71→
    72→    /// Position at edge midpoint
    73→    public func edgeMidpoint(_ edge: ScreenEdge) -> Position {
    74→        switch edge {
    75→        case .top: return Position(x: x + width / 2, y: y)
    76→        case .bottom: return Position(x: x + width / 2, y: y + height)
    77→        case .left: return Position(x: x, y: y + height / 2)
    78→        case .right: return Position(x: x + width, y: y + height / 2)
    79→        }
    80→    }
    81→}
    82→

