     1→import SwiftUI
     2→import PocketGrisCore
     3→
     4→// Disambiguate from SwiftUI.Settings
     5→typealias AppSettings = PocketGrisCore.Settings
     6→
     7→/// SwiftUI settings window for configuring Pocket Gris
     8→struct SettingsView: View {
     9→    @StateObject private var viewModel: SettingsViewModel
    10→
    11→    init(creatures: [Creature], onTestBehavior: @escaping (Creature?, BehaviorType?) -> Void, onSettingsChanged: @escaping (AppSettings) -> Void) {
    12→        _viewModel = StateObject(wrappedValue: SettingsViewModel(
    13→            creatures: creatures,
    14→            onTestBehavior: onTestBehavior,
    15→            onSettingsChanged: onSettingsChanged
    16→        ))
    17→    }
    18→
    19→    var body: some View {
    20→        Form {
    21→            appearanceSection
    22→            creaturesSection
    23→            behaviorsSection
    24→            generalSection
    25→        }
    26→        .formStyle(.grouped)
    27→        .frame(minWidth: 420, idealWidth: 450, minHeight: 500, idealHeight: 600)
    28→        .navigationTitle("Pocket Gris Settings")
    29→    }
    30→
    31→    // MARK: - Sections
    32→
    33→    private var appearanceSection: some View {
    34→        Section("Appearance Timing") {
    35→            VStack(alignment: .leading, spacing: 8) {
    36→                HStack {
    37→                    Text("Minimum interval")
    38→                    Spacer()
    39→                    Text(viewModel.formatInterval(viewModel.minInterval))
    40→                        .foregroundStyle(.secondary)
    41→                        .monospacedDigit()
    42→                }
    43→                Slider(value: $viewModel.minInterval, in: 60...3600, step: 60) {
    44→                    Text("Min")
    45→                } onEditingChanged: { _ in
    46→                    viewModel.clampIntervals()
    47→                    viewModel.applySettings()
    48→                }
    49→
    50→                HStack {
    51→                    Text("Maximum interval")
    52→                    Spacer()
    53→                    Text(viewModel.formatInterval(viewModel.maxInterval))
    54→                        .foregroundStyle(.secondary)
    55→                        .monospacedDigit()
    56→                }
    57→                Slider(value: $viewModel.maxInterval, in: 60...7200, step: 60) {
    58→                    Text("Max")
    59→                } onEditingChanged: { _ in
    60→                    viewModel.clampIntervals()
    61→                    viewModel.applySettings()
    62→                }
    63→            }
    64→        }
    65→    }
    66→
    67→    private var creaturesSection: some View {
    68→        Section("Creatures") {
    69→            if viewModel.creatures.isEmpty {
    70→                Text("No creatures loaded")
    71→                    .foregroundStyle(.secondary)
    72→            } else {
    73→                ForEach(viewModel.creatures, id: \.id) { creature in
    74→                    Toggle(isOn: viewModel.creatureBinding(for: creature.id)) {
    75→                        VStack(alignment: .leading) {
    76→                            Text(creature.name)
    77→                            Text(creature.personality.rawValue.capitalized)
    78→                                .font(.caption)
    79→                                .foregroundStyle(.secondary)
    80→                        }
    81→                    }
    82→                    .onChange(of: viewModel.enabledCreatureIds) { _ in
    83→                        viewModel.applySettings()
    84→                    }
    85→                }
    86→            }
    87→        }
    88→    }
    89→
    90→    private var behaviorsSection: some View {
    91→        Section {
    92→            ForEach(BehaviorType.allCases, id: \.self) { behaviorType in
    93→                VStack(alignment: .leading, spacing: 4) {
    94→                    HStack {
    95→                        Toggle(isOn: viewModel.behaviorEnabledBinding(for: behaviorType)) {
    96→                            Text(viewModel.behaviorDisplayName(behaviorType))
    97→                        }
    98→                        .onChange(of: viewModel.behaviorWeights[behaviorType.rawValue]) { _ in
    99→                            viewModel.applySettings()
   100→                        }
   101→                    }
   102→
   103→                    if viewModel.isBehaviorEnabled(behaviorType) {
   104→                        HStack {
   105→                            Text("Weight")
   106→                                .font(.caption)
   107→                                .foregroundStyle(.secondary)
   108→                            Slider(
   109→                                value: viewModel.behaviorWeightBinding(for: behaviorType),
   110→                                in: 0.1...3.0,
   111→                                step: 0.1
   112→                            ) {
   113→                                Text("Weight")
   114→                            } onEditingChanged: { _ in
   115→                                viewModel.applySettings()
   116→                            }
   117→                            Text(String(format: "%.1f", viewModel.behaviorWeights[behaviorType.rawValue] ?? 1.0))
   118→                                .font(.caption)
   119→                                .foregroundStyle(.secondary)
   120→                                .monospacedDigit()
   121→                                .frame(width: 30)
   122→                        }
   123→                        .padding(.leading, 20)
   124→                    }
   125→                }
   126→            }
   127→
   128→            Button("Test Random Behavior") {
   129→                viewModel.testBehavior()
   130→            }
   131→            .padding(.top, 4)
   132→        } header: {
   133→            Text("Behaviors")
   134→        } footer: {
   135→            Text("Weight controls how likely each behavior is to be chosen. Higher = more frequent.")
   136→        }
   137→    }
   138→
   139→    private var generalSection: some View {
   140→        Section("General") {
   141→            Toggle("Launch at login", isOn: $viewModel.launchAtLogin)
   142→                .onChange(of: viewModel.launchAtLogin) { _ in
   143→                    viewModel.applySettings()
   144→                }
   145→
   146→            Button("Reset to Defaults") {
   147→                viewModel.resetToDefaults()
   148→            }
   149→        }
   150→    }
   151→}
