   153→// MARK: - View Model
   154→
   155→@MainActor
   156→final class SettingsViewModel: ObservableObject {
   157→    @Published var minInterval: TimeInterval
   158→    @Published var maxInterval: TimeInterval
   159→    @Published var launchAtLogin: Bool
   160→    @Published var enabledCreatureIds: Set<String>
   161→    @Published var behaviorWeights: [String: Double]
   162→
   163→    let creatures: [Creature]
   164→    private let onTestBehavior: (Creature?, BehaviorType?) -> Void
   165→    private let onSettingsChanged: (AppSettings) -> Void
   166→
   167→    init(creatures: [Creature], onTestBehavior: @escaping (Creature?, BehaviorType?) -> Void, onSettingsChanged: @escaping (AppSettings) -> Void) {
   168→        let settings = AppSettings.load()
   169→        self.minInterval = settings.minInterval
   170→        self.maxInterval = settings.maxInterval
   171→        self.launchAtLogin = settings.launchAtLogin
   172→        self.enabledCreatureIds = settings.enabledCreatures
   173→        self.behaviorWeights = settings.behaviorWeights
   174→        self.creatures = creatures
   175→        self.onTestBehavior = onTestBehavior
   176→        self.onSettingsChanged = onSettingsChanged
   177→    }
   178→
   179→    // MARK: - Bindings
   180→
   181→    func creatureBinding(for id: String) -> Binding<Bool> {
   182→        Binding(
   183→            get: {
   184→                // Empty set means all enabled
   185→                self.enabledCreatureIds.isEmpty || self.enabledCreatureIds.contains(id)
   186→            },
   187→            set: { enabled in
   188→                // If toggling off and set is empty, populate with all except this one
   189→                if !enabled && self.enabledCreatureIds.isEmpty {
   190→                    self.enabledCreatureIds = Set(self.creatures.map(\.id))
   191→                    self.enabledCreatureIds.remove(id)
   192→                } else if enabled {
   193→                    self.enabledCreatureIds.insert(id)
   194→                    // If all are now enabled, clear the set (empty = all)
   195→                    if self.enabledCreatureIds.count == self.creatures.count {
   196→                        self.enabledCreatureIds.removeAll()
   197→                    }
   198→                } else {
   199→                    self.enabledCreatureIds.remove(id)
   200→                }
   201→            }
   202→        )
   203→    }
   204→
   205→    func behaviorEnabledBinding(for type: BehaviorType) -> Binding<Bool> {
   206→        Binding(
   207→            get: { self.isBehaviorEnabled(type) },
   208→            set: { enabled in
   209→                if enabled {
   210→                    self.behaviorWeights[type.rawValue] = 1.0
   211→                } else {
   212→                    self.behaviorWeights[type.rawValue] = 0.0
   213→                }
   214→                self.applySettings()
   215→            }
   216→        )
   217→    }
