    16→/// Global cursor tracker using NSEvent monitors
    17→/// Tracks cursor position system-wide, not just within our app's windows
    18→public final class GlobalCursorTracker: CursorTracker, @unchecked Sendable {
    19→    private let lock = NSLock()
    20→    private var currentPosition: Position?
    21→    private var previousPosition: Position?
    22→    private var lastUpdateTime: TimeInterval = 0
    23→    private var velocity: Position = .zero
    24→
    25→    #if canImport(AppKit)
    26→    private var globalMonitor: Any?
    27→    private var localMonitor: Any?
    28→    #endif
    29→
    30→    /// Update rate for velocity calculation (seconds)
    31→    private let velocitySmoothing: Double = 0.1
    32→
    33→    public init() {
    34→        startMonitoring()
    35→    }
    36→
    37→    deinit {
    38→        stopMonitoring()
    39→    }
    40→
    41→    public func getCurrentPosition() -> Position? {
    42→        lock.lock()
    43→        defer { lock.unlock() }
    44→        return currentPosition
    45→    }
    46→
    47→    public func getCursorVelocity() -> Position? {
    48→        lock.lock()
    49→        defer { lock.unlock() }
