    53→    // MARK: - Monitoring
    54→
    55→    private func startMonitoring() {
    56→        #if canImport(AppKit)
    57→        // Initial position from NSEvent.mouseLocation
    58→        updatePositionFromSystemCursor()
    59→
    60→        // Global monitor for events outside our app
    61→        globalMonitor = NSEvent.addGlobalMonitorForEvents(
    62→            matching: [.mouseMoved, .leftMouseDragged, .rightMouseDragged, .otherMouseDragged]
    63→        ) { [weak self] event in
    64→            self?.handleMouseEvent(event)
    65→        }
    66→
    67→        // Local monitor for events within our app
    68→        localMonitor = NSEvent.addLocalMonitorForEvents(
    69→            matching: [.mouseMoved, .leftMouseDragged, .rightMouseDragged, .otherMouseDragged]
