     7→/// Protocol for tracking window positions on screen
     8→public protocol WindowTracker: Sendable {
     9→    /// Get current window frames (excluding menubar, dock, and own windows)
    10→    func getWindowFrames() -> [ScreenRect]
    11→}
    12→
    13→/// System window tracker using macOS Accessibility APIs
    14→public final class AccessibilityWindowTracker: WindowTracker, @unchecked Sendable {
    15→    private let excludedBundleIds: Set<String>
    16→    private let lock = NSLock()
    17→
    18→    public init(excludedBundleIds: Set<String> = []) {
    19→        var excluded = excludedBundleIds
    20→        // Always exclude our own app
    21→        if let bundleId = Bundle.main.bundleIdentifier {
    22→            excluded.insert(bundleId)
    23→        }
    24→        // Exclude system UI elements
    25→        excluded.insert("com.apple.dock")
    26→        excluded.insert("com.apple.controlcenter")
    27→        excluded.insert("com.apple.notificationcenterui")
    28→        self.excludedBundleIds = excluded
    29→    }
    30→
    31→    public func getWindowFrames() -> [ScreenRect] {
    32→        #if canImport(AppKit)
    33→        lock.lock()
    34→        defer { lock.unlock() }
    35→
    36→        var frames: [ScreenRect] = []
    37→
    38→        // Get all windows using CGWindowListCopyWindowInfo
    39→        let options: CGWindowListOption = [.optionOnScreenOnly, .excludeDesktopElements]
    40→        guard let windowList = CGWindowListCopyWindowInfo(options, kCGNullWindowID) as? [[String: Any]] else {
    41→            return frames
    42→        }
    43→
    44→        for windowInfo in windowList {
    45→            // Skip windows without bounds
    46→            guard let boundsDict = windowInfo[kCGWindowBounds as String] as? [String: Any],
    47→                  let x = boundsDict["X"] as? Double,
    48→                  let y = boundsDict["Y"] as? Double,
    49→                  let width = boundsDict["Width"] as? Double,
    50→                  let height = boundsDict["Height"] as? Double else {
    51→                continue
    52→            }
    53→
    54→            // Skip tiny windows (likely system elements)
    55→            guard width > 50 && height > 50 else {
    56→                continue
    57→            }
    58→
    59→            // Skip excluded apps
    60→            if let ownerPID = windowInfo[kCGWindowOwnerPID as String] as? Int32 {
    61→                if let app = NSRunningApplication(processIdentifier: ownerPID),
    62→                   let bundleId = app.bundleIdentifier,
    63→                   excludedBundleIds.contains(bundleId) {
    64→                    continue
    65→                }
    66→            }
    67→
    68→            // Skip windows with low layer (desktop background)
    69→            if let layer = windowInfo[kCGWindowLayer as String] as? Int, layer < 0 {
    70→                continue
    71→            }
    72→
    73→            frames.append(ScreenRect(x: x, y: y, width: width, height: height))
    74→        }
    75→
    76→        return frames
    77→        #else
    78→        return []
    79→        #endif
    80→    }
    81→}
