   112→// MARK: - ScreenRect Extensions for Window Edges
   113→
   114→extension ScreenRect {
   115→    /// Edges available for climbing (left, right, top, bottom of window)
   116→    public enum WindowEdge: CaseIterable {
   117→        case top, bottom, left, right
   118→    }
   119→
   120→    /// Get a random position along a window edge
   121→    public func randomPositionOnEdge(_ edge: WindowEdge, random: RandomSource, margin: Double = 20) -> Position {
   122→        switch edge {
   123→        case .top:
   124→            let x = random.double(in: (minX + margin)...(maxX - margin))
   125→            return Position(x: x, y: minY)
   126→        case .bottom:
   127→            let x = random.double(in: (minX + margin)...(maxX - margin))
   128→            return Position(x: x, y: maxY)
   129→        case .left:
   130→            let y = random.double(in: (minY + margin)...(maxY - margin))
   131→            return Position(x: minX, y: y)
   132→        case .right:
   133→            let y = random.double(in: (minY + margin)...(maxY - margin))
   134→            return Position(x: maxX, y: y)
   135→        }
   136→    }
   137→
   138→    /// Position at the corner between two edges
   139→    public func cornerPosition(primary: WindowEdge, secondary: WindowEdge) -> Position {
   140→        switch (primary, secondary) {
   141→        case (.top, .left), (.left, .top):
   142→            return Position(x: minX, y: minY)
   143→        case (.top, .right), (.right, .top):
   144→            return Position(x: maxX, y: minY)
   145→        case (.bottom, .left), (.left, .bottom):
   146→            return Position(x: minX, y: maxY)
   147→        case (.bottom, .right), (.right, .bottom):
   148→            return Position(x: maxX, y: maxY)
   149→        default:
   150→            return center
   151→        }
   152→    }
   153→
   154→    /// Check if a position is near this window's edge
   155→    public func isNearEdge(_ position: Position, threshold: Double = 30) -> WindowEdge? {
   156→        // Check if within bounds + threshold
   157→        let expanded = ScreenRect(
   158→            x: x - threshold,
   159→            y: y - threshold,
   160→            width: width + threshold * 2,
   161→            height: height + threshold * 2
   162→        )
   163→        guard expanded.contains(position) else { return nil }
   164→
   165→        // Find nearest edge
   166→        let distTop = abs(position.y - minY)
   167→        let distBottom = abs(position.y - maxY)
   168→        let distLeft = abs(position.x - minX)
   169→        let distRight = abs(position.x - maxX)
   170→
   171→        let minDist = min(distTop, distBottom, distLeft, distRight)
   172→
   173→        if minDist > threshold { return nil }
   174→
   175→        if minDist == distTop { return .top }
   176→        if minDist == distBottom { return .bottom }
   177→        if minDist == distLeft { return .left }
   178→        return .right
   179→    }
   180→}
