    43→
    44→    public func setTriggerHandler(_ handler: @escaping TriggerHandler) {
    45→        lock.lock()
    46→        defer { lock.unlock() }
    47→        self.onTrigger = handler
    48→    }
    49→
    50→    // MARK: - Control
    51→
    52→    public func start() {
    53→        lock.lock()
    54→        defer { lock.unlock() }
