    65→        isRunning = false
    66→        timer?.cancel()
    67→        timer = nil
    68→    }
    69→
    70→    public func triggerNow(creature: Creature? = nil, behavior: BehaviorType? = nil) {
    71→        lock.lock()
    72→        let handler = onTrigger
    73→        let selectedCreature = creature ?? selectRandomCreature()
    74→        let selectedBehavior: BehaviorType?
    75→        if let c = selectedCreature {
    76→            selectedBehavior = behavior ?? selectRandomBehavior(for: c)
    77→        } else {
    78→            selectedBehavior = nil
    79→        }
    80→        lock.unlock()
    81→
    82→        guard let c = selectedCreature, let b = selectedBehavior else { return }
    83→        handler?(c, b)
    84→    }
    85→
    86→    // MARK: - Simulation
    87→
    88→    /// Simulate scheduling for testing/preview
    89→    public func simulate(duration: TimeInterval) -> [(time: TimeInterval, creature: String, behavior: BehaviorType)] {
    90→        var results: [(TimeInterval, String, BehaviorType)] = []
    91→        var elapsed: TimeInterval = 0
    92→
    93→        while elapsed < duration {
    94→            let interval = settings.randomInterval(using: random)
    95→            elapsed += interval
    96→
    97→            if elapsed < duration {
    98→                if let creature = selectRandomCreature(),
    99→                   let behavior = selectRandomBehavior(for: creature) {
   100→                    results.append((elapsed, creature.id, behavior))
   101→                }
   102→            }
   103→        }
   104→
   105→        return results
   106→    }
