   108→    // MARK: - Private
   109→
   110→    private func scheduleNextTrigger() {
   111→        guard isRunning else { return }
   112→
   113→        let interval = settings.randomInterval(using: random)
   114→        nextTriggerTime = timeSource.now + interval
   115→
   116→        timer?.cancel()
   117→
   118→        let timer = DispatchSource.makeTimerSource(queue: .main)
   119→        timer.schedule(deadline: .now() + interval)
   120→        timer.setEventHandler { [weak self] in
   121→            self?.handleTrigger()
   122→        }
   123→        self.timer = timer
   124→        timer.resume()
   125→    }
   126→
   127→    private func handleTrigger() {
   128→        lock.lock()
   129→        guard isRunning, settings.enabled else {
   130→            lock.unlock()
   131→            return
   132→        }
   133→
   134→        let handler = onTrigger
   135→        let creature = selectRandomCreature()
   136→        let behavior = creature.flatMap { selectRandomBehavior(for: $0) }
   137→        lock.unlock()
   138→
   139→        if let c = creature, let b = behavior {
   140→            handler?(c, b)
   141→        }
   142→
   143→        lock.lock()
   144→        scheduleNextTrigger()
   145→        lock.unlock()
   146→    }
