   148→    private func selectRandomCreature() -> Creature? {
   149→        var pool = creatures
   150→
   151→        // Filter by enabled creatures if specified
   152→        if !settings.enabledCreatures.isEmpty {
   153→            pool = pool.filter { settings.enabledCreatures.contains($0.id) }
   154→        }
   155→
   156→        guard !pool.isEmpty else { return nil }
   157→
   158→        let index = random.int(in: 0..<pool.count)
   159→        return pool[index]
   160→    }
   161→
   162→    private func selectRandomBehavior(for creature: Creature) -> BehaviorType? {
   163→        let available = BehaviorRegistry.shared.availableBehaviors(for: creature)
   164→        guard !available.isEmpty else { return nil }
   165→
   166→        // Apply behavior weights
   167→        let weighted: [(BehaviorType, Double)] = available.map { behavior in
   168→            let weight = settings.behaviorWeights[behavior.type.rawValue] ?? 1.0
   169→            return (behavior.type, weight)
   170→        }
   171→
   172→        let totalWeight = weighted.reduce(0) { $0 + $1.1 }
   173→        guard totalWeight > 0 else { return available.first?.type }
   174→
   175→        var roll = random.double(in: 0...totalWeight)
   176→        for (type, weight) in weighted {
   177→            roll -= weight
   178→            if roll <= 0 {
   179→                return type
   180→            }
   181→        }
   182→
   183→        return available.first?.type
   184→    }
   185→}
