import Foundation

/// Protocol for creature behaviors
public protocol Behavior: Sendable {
    /// The type of this behavior
    var type: BehaviorType { get }

    /// Required animations for this behavior
    var requiredAnimations: [String] { get }

    /// Initialize behavior state
    func start(context: BehaviorContext, random: RandomSource) -> BehaviorState

    /// Update behavior state, returns events generated
    func update(
        state: inout BehaviorState,
        context: BehaviorContext,
        deltaTime: TimeInterval
    ) -> [BehaviorEvent]

    /// Cancel behavior, transition to exit
    func cancel(state: inout BehaviorState) -> [BehaviorEvent]
}

// MARK: - Behavior Registry

/// Registry of available behaviors
public final class BehaviorRegistry: @unchecked Sendable {
    public static let shared = BehaviorRegistry()

    private var behaviors: [BehaviorType: any Behavior] = [:]
    private let lock = NSLock()

    private init() {
        // Register default behaviors
        register(PeekBehavior())
        register(TraverseBehavior())
        register(StationaryBehavior())
        register(ClimberBehavior())
        register(FollowBehavior())
    }

    public func register(_ behavior: any Behavior) {
        lock.lock()
        defer { lock.unlock() }
        behaviors[behavior.type] = behavior
    }

    public func behavior(for type: BehaviorType) -> (any Behavior)? {
        lock.lock()
        defer { lock.unlock() }
        return behaviors[type]
    }

    public func allBehaviors() -> [any Behavior] {
        lock.lock()
        defer { lock.unlock() }
        return Array(behaviors.values)
    }

    public func availableBehaviors(for creature: Creature) -> [any Behavior] {
        allBehaviors().filter { behavior in
            behavior.requiredAnimations.allSatisfy { creature.animations[$0] != nil }
        }
    }
}

import Foundation

/// Types of behaviors creatures can perform
public enum BehaviorType: String, CaseIterable, Codable, Sendable {
    case peek           // Teleport to edge, peek, retreat
    case traverse       // Walk across screen
    case stationary     // Appear, do antics, disappear
    case climber        // Climb window edges
    case cursorReactive // React to mouse position
}

/// State machine phases for behavior execution
public enum BehaviorPhase: String, Equatable, Sendable {
    case idle           // Not active
    case enter          // Appearing/entering
    case perform        // Main action
    case exit           // Leaving/disappearing
    case complete       // Finished
}

/// Current state of a behavior instance
public struct BehaviorState: Equatable, Sendable {
    public var phase: BehaviorPhase
    public var position: Position
    public var animation: AnimationState?
    public var edge: ScreenEdge?
    public var startTime: TimeInterval
    public var duration: TimeInterval
    public var metadata: [String: String]

    public init(
        phase: BehaviorPhase = .idle,
        position: Position = .zero,
        animation: AnimationState? = nil,
        edge: ScreenEdge? = nil,
        startTime: TimeInterval = 0,
        duration: TimeInterval = 0,
        metadata: [String: String] = [:]
    ) {
        self.phase = phase
        self.position = position
        self.animation = animation
        self.edge = edge
        self.startTime = startTime
        self.duration = duration
        self.metadata = metadata
    }
}

/// Events that behaviors can emit
public enum BehaviorEvent: Equatable, Sendable {
    case started(BehaviorType)
    case phaseChanged(BehaviorPhase)
    case positionChanged(Position)
    case animationFrameChanged(Int)
    case completed
    case cancelled
}

/// Context provided to behaviors
public struct BehaviorContext: Sendable {
    public let creature: Creature
    public let screenBounds: ScreenRect
    public let currentTime: TimeInterval
    public let cursorPosition: Position?
    public let windowFrames: [ScreenRect]

    public init(
        creature: Creature,
        screenBounds: ScreenRect,
        currentTime: TimeInterval,
        cursorPosition: Position? = nil,
        windowFrames: [ScreenRect] = []
    ) {
        self.creature = creature
        self.screenBounds = screenBounds
        self.currentTime = currentTime
        self.cursorPosition = cursorPosition
        self.windowFrames = windowFrames
    }
}

import AppKit
import PocketGrisCore

final class AppDelegate: NSObject, NSApplicationDelegate {

    private var statusItem: NSStatusItem!
    private var creatureWindow: CreatureWindow?
    private let spriteLoader = SpriteLoader()
    private let scheduler = BehaviorScheduler()
    private let ipcService = IPCService()
    private let windowTracker = AccessibilityWindowTracker()
    private let cursorTracker = GlobalCursorTracker()
    private var isEnabled = true
    private let settingsWindowController = SettingsWindowController()

    func applicationDidFinishLaunching(_ notification: Notification) {
        setupMenuBar()
        setupIPC()
        loadCreatures()
        startScheduler()
    }

    func applicationWillTerminate(_ notification: Notification) {
        ipcService.stopListening()
        ipcService.markGUIRunning(false)
        scheduler.stop()
    }

    // MARK: - Menu Bar

    private func setupMenuBar() {
        statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)

        if let button = statusItem.button {
            button.image = NSImage(systemSymbolName: "pawprint.fill", accessibilityDescription: "Pocket Gris")
            button.image?.isTemplate = true
        }

        let menu = NSMenu()

        menu.addItem(NSMenuItem(title: "Trigger Now", action: #selector(triggerNow), keyEquivalent: "t"))
        menu.addItem(NSMenuItem.separator())

        let enableItem = NSMenuItem(title: "Enabled", action: #selector(toggleEnabled), keyEquivalent: "e")
        enableItem.state = isEnabled ? .on : .off
        menu.addItem(enableItem)

        menu.addItem(NSMenuItem.separator())
        menu.addItem(NSMenuItem(title: "Settings...", action: #selector(openSettings), keyEquivalent: ","))
        menu.addItem(NSMenuItem.separator())
        menu.addItem(NSMenuItem(title: "Quit", action: #selector(quit), keyEquivalent: "q"))

        statusItem.menu = menu
    }

    @objc private func triggerNow() {
        scheduler.triggerNow()
    }

    @objc private func toggleEnabled() {
        isEnabled.toggle()
        updateMenuState()

        var settings = Settings.load()
        settings.enabled = isEnabled
        try? settings.save()
        scheduler.updateSettings(settings)
    }

    @objc private func openSettings() {
        let creatures = spriteLoader.allCreatures()
        settingsWindowController.show(
            creatures: creatures,
            onTestBehavior: { [weak self] creature, behavior in
                if let creature = creature {
                    let behaviorType = behavior ?? .peek
                    self?.showCreature(creature, behavior: behaviorType)
                } else {
                    self?.scheduler.triggerNow()
                }
            },
            onSettingsChanged: { [weak self] settings in
                self?.scheduler.updateSettings(settings)
            }
        )
    }

    @objc private func quit() {
        NSApp.terminate(nil)
    }

    private func updateMenuState() {
        guard let menu = statusItem.menu else { return }
        for item in menu.items where item.action == #selector(toggleEnabled) {
            item.state = isEnabled ? .on : .off
        }
    }

    // MARK: - IPC

    private func setupIPC() {
        ipcService.markGUIRunning(true)
        ipcService.startListening { [weak self] message in
            self?.handleIPCMessage(message) ?? IPCResponse(success: false, message: "App not ready")
        }
    }

    private func handleIPCMessage(_ message: IPCMessage) -> IPCResponse {
        switch message.command {
        case .trigger:
            DispatchQueue.main.async { [weak self] in
                if let creatureId = message.creature,
                   let creature = self?.spriteLoader.creature(id: creatureId) {
                    let behavior = message.behavior.flatMap { BehaviorType(rawValue: $0) }
                    self?.scheduler.triggerNow(creature: creature, behavior: behavior)
                } else {
                    self?.scheduler.triggerNow()
                }
            }
            return IPCResponse(success: true, message: "Triggered")

        case .enable:
            DispatchQueue.main.async { [weak self] in
                self?.isEnabled = true
                self?.updateMenuState()
                var settings = Settings.load()
                settings.enabled = true
                try? settings.save()
                self?.scheduler.updateSettings(settings)
            }
            return IPCResponse(success: true, message: "Enabled")

        case .disable:
            DispatchQueue.main.async { [weak self] in
                self?.isEnabled = false
                self?.updateMenuState()
                var settings = Settings.load()
                settings.enabled = false
                try? settings.save()
                self?.scheduler.updateSettings(settings)
            }
            return IPCResponse(success: true, message: "Disabled")

        case .cancel:
            DispatchQueue.main.async { [weak self] in
                self?.creatureWindow?.close()
                self?.creatureWindow = nil
            }
            return IPCResponse(success: true, message: "Cancelled")

        case .status:
            let creatures = spriteLoader.allCreatures()
            return IPCResponse(
                success: true,
                message: nil,
                data: [
                    "enabled": String(isEnabled),
                    "creatures": String(creatures.count),
                    "windowVisible": String(creatureWindow != nil)
                ]
            )
        }
    }

    // MARK: - Creatures

    private func loadCreatures() {
        let creatures = spriteLoader.loadAllCreatures()
        scheduler.updateCreatures(creatures)
        print("Loaded \(creatures.count) creatures")

        if creatures.isEmpty {
            print("No creatures found in Resources/Sprites/")
            print("Add sprite folders with creature.json manifests")
        }
    }

    private func startScheduler() {
        let settings = Settings.load()
        scheduler.updateSettings(settings)
        isEnabled = settings.enabled

        scheduler.setTriggerHandler { [weak self] creature, behaviorType in
            self?.showCreature(creature, behavior: behaviorType)
        }

        scheduler.start()
    }

    private func showCreature(_ creature: Creature, behavior behaviorType: BehaviorType) {
        guard isEnabled else { return }

        // Close any existing window
        creatureWindow?.close()

        // Pick a random screen for multi-monitor support
        let screens = NSScreen.screens
        let targetScreen = screens.isEmpty ? nil : screens[Int.random(in: 0..<screens.count)]

        // Create and show new creature window
        let window = CreatureWindow(screen: targetScreen)
        window.show(
            creature: creature,
            behavior: behaviorType,
            spriteLoader: spriteLoader,
