import Foundation

/// Schedules creature appearances at random intervals
public final class BehaviorScheduler: @unchecked Sendable {
    public typealias TriggerHandler = (Creature, BehaviorType) -> Void

    private var settings: Settings
    private var creatures: [Creature]
    private var timeSource: TimeSource
    private var random: RandomSource
    private var onTrigger: TriggerHandler?

    private var timer: DispatchSourceTimer?
    private var nextTriggerTime: TimeInterval = 0
    private var isRunning = false
    private let lock = NSLock()

    public init(
        settings: Settings = .default,
        creatures: [Creature] = [],
        timeSource: TimeSource = SystemTimeSource(),
        random: RandomSource = SystemRandomSource()
    ) {
        self.settings = settings
        self.creatures = creatures
        self.timeSource = timeSource
        self.random = random
    }

    // MARK: - Configuration

    public func updateSettings(_ settings: Settings) {
        lock.lock()
        defer { lock.unlock() }
        self.settings = settings
    }

    public func updateCreatures(_ creatures: [Creature]) {
        lock.lock()
        defer { lock.unlock() }
        self.creatures = creatures
    }

    public func setTriggerHandler(_ handler: @escaping TriggerHandler) {
        lock.lock()
        defer { lock.unlock() }
        self.onTrigger = handler
    }

    // MARK: - Control

    public func start() {
        lock.lock()
        defer { lock.unlock() }

        guard !isRunning else { return }
        isRunning = true
        scheduleNextTrigger()
    }

    public func stop() {
        lock.lock()
        defer { lock.unlock() }

        isRunning = false
        timer?.cancel()
        timer = nil
    }

    public func triggerNow(creature: Creature? = nil, behavior: BehaviorType? = nil) {
        lock.lock()
        let handler = onTrigger
        let selectedCreature = creature ?? selectRandomCreature()
        let selectedBehavior: BehaviorType?
        if let c = selectedCreature {
            selectedBehavior = behavior ?? selectRandomBehavior(for: c)
        } else {
            selectedBehavior = nil
        }
        lock.unlock()

        guard let c = selectedCreature, let b = selectedBehavior else { return }
        handler?(c, b)
    }

    // MARK: - Simulation

    /// Simulate scheduling for testing/preview
    public func simulate(duration: TimeInterval) -> [(time: TimeInterval, creature: String, behavior: BehaviorType)] {
        var results: [(TimeInterval, String, BehaviorType)] = []
        var elapsed: TimeInterval = 0

        while elapsed < duration {
            let interval = settings.randomInterval(using: random)
            elapsed += interval

            if elapsed < duration {
                if let creature = selectRandomCreature(),
                   let behavior = selectRandomBehavior(for: creature) {
                    results.append((elapsed, creature.id, behavior))
                }
            }
        }

        return results
    }

    // MARK: - Private

    private func scheduleNextTrigger() {
        guard isRunning else { return }

        let interval = settings.randomInterval(using: random)
        nextTriggerTime = timeSource.now + interval

        timer?.cancel()

        let timer = DispatchSource.makeTimerSource(queue: .main)
        timer.schedule(deadline: .now() + interval)
        timer.setEventHandler { [weak self] in
            self?.handleTrigger()
        }
        self.timer = timer
        timer.resume()
    }

    private func handleTrigger() {
        lock.lock()
        guard isRunning, settings.enabled else {
            lock.unlock()
            return
        }

        let handler = onTrigger
        let creature = selectRandomCreature()
        let behavior = creature.flatMap { selectRandomBehavior(for: $0) }
        lock.unlock()

        if let c = creature, let b = behavior {
            handler?(c, b)
        }

        lock.lock()
        scheduleNextTrigger()
        lock.unlock()
    }

    private func selectRandomCreature() -> Creature? {
        var pool = creatures

        // Filter by enabled creatures if specified
        if !settings.enabledCreatures.isEmpty {
            pool = pool.filter { settings.enabledCreatures.contains($0.id) }
        }

        guard !pool.isEmpty else { return nil }

        let index = random.int(in: 0..<pool.count)
        return pool[index]
    }

    private func selectRandomBehavior(for creature: Creature) -> BehaviorType? {
        let available = BehaviorRegistry.shared.availableBehaviors(for: creature)
        guard !available.isEmpty else { return nil }

        // Apply behavior weights
        let weighted: [(BehaviorType, Double)] = available.map { behavior in
            let weight = settings.behaviorWeights[behavior.type.rawValue] ?? 1.0
            return (behavior.type, weight)
        }

        let totalWeight = weighted.reduce(0) { $0 + $1.1 }
        guard totalWeight > 0 else { return available.first?.type }

        var roll = random.double(in: 0...totalWeight)
        for (type, weight) in weighted {
            roll -= weight
            if roll <= 0 {
                return type
            }
        }

        return available.first?.type
    }
}

import AppKit
import SwiftUI
import PocketGrisCore

/// A transparent, floating, click-through window for displaying creatures
final class CreatureWindow: NSWindow {

    private var viewModel: CreatureViewModel?
    private var displayLink: CVDisplayLink?
    private var lastFrameTime: CFTimeInterval = 0
    private var onComplete: (() -> Void)?

    init(screen: NSScreen? = nil) {
        let targetScreen = screen ?? NSScreen.main
        let screenFrame = targetScreen?.frame ?? NSRect(x: 0, y: 0, width: 1920, height: 1080)

        super.init(
            contentRect: screenFrame,
            styleMask: [.borderless],
            backing: .buffered,
            defer: false
        )

        // Configure window for floating transparent overlay
        self.isOpaque = false
        self.backgroundColor = .clear
        self.hasShadow = false
        self.level = .floating
        self.collectionBehavior = [.canJoinAllSpaces, .stationary, .ignoresCycle]
        self.ignoresMouseEvents = true
        self.isReleasedWhenClosed = false
    }

    func show(
        creature: Creature,
        behavior behaviorType: BehaviorType,
        spriteLoader: SpriteLoader,
        windowTracker: WindowTracker? = nil,
        cursorTracker: CursorTracker? = nil,
        onComplete: @escaping () -> Void
    ) {
        self.onComplete = onComplete

        // Create view model
        let screenBounds = ScreenRect(
            x: frame.origin.x,
            y: frame.origin.y,
            width: frame.width,
            height: frame.height
        )

        viewModel = CreatureViewModel(
            creature: creature,
            behaviorType: behaviorType,
            screenBounds: screenBounds,
            spriteLoader: spriteLoader,
            windowTracker: windowTracker,
            cursorTracker: cursorTracker
        )

        viewModel?.onComplete = { [weak self] in
            DispatchQueue.main.async {
                self?.close()
                self?.onComplete?()
            }
        }

        // Create SwiftUI view
        let spriteView = SpriteView(viewModel: viewModel!)
        let hostingView = NSHostingView(rootView: spriteView)
        hostingView.frame = contentView?.bounds ?? frame

        contentView = hostingView

        // Show window
        makeKeyAndOrderFront(nil)

        // Start behavior
        viewModel?.start()

        // Start animation loop
        startDisplayLink()
    }

    override func close() {
        stopDisplayLink()
        viewModel?.cancel()
        super.close()
    }

    // MARK: - Display Link

    private func startDisplayLink() {
        var link: CVDisplayLink?
        CVDisplayLinkCreateWithActiveCGDisplays(&link)
        guard let displayLink = link else { return }

        self.displayLink = displayLink
        lastFrameTime = CACurrentMediaTime()

        let callback: CVDisplayLinkOutputCallback = { _, _, _, _, _, userInfo -> CVReturn in
            guard let userInfo = userInfo else { return kCVReturnSuccess }
            let window = Unmanaged<CreatureWindow>.fromOpaque(userInfo).takeUnretainedValue()
            window.handleFrame()
            return kCVReturnSuccess
        }

        let userInfo = Unmanaged.passUnretained(self).toOpaque()
        CVDisplayLinkSetOutputCallback(displayLink, callback, userInfo)
        CVDisplayLinkStart(displayLink)
    }

    private func stopDisplayLink() {
        guard let link = displayLink else { return }
        CVDisplayLinkStop(link)
        displayLink = nil
    }

    private func handleFrame() {
        let now = CACurrentMediaTime()
        let deltaTime = now - lastFrameTime
        lastFrameTime = now

        DispatchQueue.main.async { [weak self] in
            self?.viewModel?.update(deltaTime: deltaTime)
        }
    }
}

import Foundation

/// Application settings
public struct Settings: Equatable, Codable, Sendable {
    /// Whether creatures are enabled
    public var enabled: Bool

    /// Minimum interval between appearances (seconds)
    public var minInterval: TimeInterval

    /// Maximum interval between appearances (seconds)
    public var maxInterval: TimeInterval

    /// Launch at login
    public var launchAtLogin: Bool

    /// Enabled creature IDs (empty = all enabled)
    public var enabledCreatures: Set<String>

    /// Behavior weights for scheduler
    public var behaviorWeights: [String: Double]

    public init(
        enabled: Bool = true,
        minInterval: TimeInterval = 15 * 60,  // 15 minutes
        maxInterval: TimeInterval = 30 * 60,  // 30 minutes
        launchAtLogin: Bool = false,
        enabledCreatures: Set<String> = [],
        behaviorWeights: [String: Double] = [:]
    ) {
        self.enabled = enabled
        self.minInterval = minInterval
        self.maxInterval = maxInterval
        self.launchAtLogin = launchAtLogin
        self.enabledCreatures = enabledCreatures
        self.behaviorWeights = behaviorWeights
    }

    /// Default settings
    public static let `default` = Settings()

    /// Random interval within configured range
    public func randomInterval(using random: RandomSource = SystemRandomSource()) -> TimeInterval {
        random.double(in: minInterval...maxInterval)
    }
}

// MARK: - Persistence

extension Settings {
    private static var settingsURL: URL {
        let appSupport = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        let dir = appSupport.appendingPathComponent("PocketGris", isDirectory: true)
        try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        return dir.appendingPathComponent("settings.json")
    }

    public static func load() -> Settings {
        guard let data = try? Data(contentsOf: settingsURL),
              let settings = try? JSONDecoder().decode(Settings.self, from: data) else {
            return .default
        }
        return settings
    }

    public func save() throws {
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        let data = try encoder.encode(self)
        try data.write(to: Self.settingsURL)
    }
}

